{
var seed = GetInt(parameters, "seed", context.Seed);
var waveType = GetChoice(parameters, "waveType", "sine");
var freqX = GetFloat(parameters, "freqX", 4);
var freqY = GetFloat(parameters, "freqY", 4);
var amp = GetFloat(parameters, "amplitude", 0.5f);
var phase = GetFloat(parameters, "phase", 0);
var sharpness = GetFloat(parameters, "sharpness", 0.5f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var noiseField = new PixelBuffer(size, size);
if (waveType == "ripple")
{
    noiseField.ParallelForEachPixel((x, y) =>
    {
        var u = (x + 0.5f) / size * 2f - 1f;
        var v = (y + 0.5f) / size * 2f - 1f;
        var r = MathF.Sqrt(u * u + v * v);

        // Moire/interference pattern from multiple ripple sources
        var val = 0f;
        for (var i = 0; i < 3; i++)
        {
            var srcX = (HashToUnit(i * 7, seed, 111) - 0.5f) * 1.5f;
            var srcY = (HashToUnit(i * 13, seed * 3, 222) - 0.5f) * 1.5f;
            var dx = u - srcX;
            var dy = v - srcY;
            var d = MathF.Sqrt(dx * dx + dy * dy);
            val += MathF.Sin(d * freqX * MathF.PI * 2f + phase + i * 1.5f) * amp;
        }
        val = val / 3f * 0.5f + 0.5f;
        buffer.SetPixel(x, y, val, val, val, 1f);
    });
    return buffer;
}

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    var t = u * freqX * MathF.PI * 2f + v * freqY * MathF.PI * 2f + phase;
    var val = 0f;

    switch (waveType)
    {
        case "square":
            val = MathF.Sin(t) > 0f ? 1f : -1f;
            // Soften edge based on sharpness
            if (sharpness < 1f)
            {
                var soft = MathF.Abs(MathF.Sin(t));
                var blend = MathF.Pow(soft, 1f - sharpness * 0.9f);
                val *= blend;
            }
            break;
        case "triangle":
        {
            var norm = t / (MathF.PI * 2f);
            var frac = norm - MathF.Floor(norm);
            val = frac < 0.25f ? frac * 4f :
                  frac < 0.75f ? 2f - frac * 4f :
                  frac * 4f - 4f;
            break;
        }
        case "sawtooth":
        {
            var norm = t / (MathF.PI * 2f);
            var frac = norm - MathF.Floor(norm);
            val = 1f - frac * 2f;
            // Soften
            if (sharpness < 1f)
            {
                var edge = MathF.Min(frac, 1f - frac) * 2f;
                var smooth = MathF.Pow(edge, sharpness * 2f + 0.5f);
                val *= smooth;
            }
            break;
        }
        default: // sine
            val = MathF.Sin(t);
            break;
    }

    // Apply noise modulation
    var noise = TileableFractalNoise(u * 3f, v * 3f, 8, 2, 0.5f, 2f, seed);
    val *= (0.9f + noise * 0.1f);

    val = val * amp * 0.5f + 0.5f;
    val = Math.Clamp(val, 0f, 1f);

    if (invert) val = 1f - val;

    buffer.SetPixel(x, y, val, val, val, 1f);
});

return buffer;
}
